#!/usr/bin/env python3
import json
import sys
import re

# Terms that indicate a query has slipped into the wrong domain
GAMING_TERMS = [
    "minecraft", "game", "gaming", "multiplayer", "player", "block game",
    "server game", "mod", "modding", "world", "spawn", "biome"
]

CONSUMER_TERMS = [
    "shopping", "product review", "buy", "price", "store", "retailer"
]

# Known technical acronyms and their correct expansions
# Used to detect when an acronym has been incorrectly expanded
TECH_ACRONYMS = {
    "mcp": "model context protocol",
    "rag": "retrieval augmented generation",
    "llm": "large language model",
    "api": "application programming interface",
    "sdk": "software development kit",
    "cli": "command line interface",
    "orm": "object relational mapping",
    "rpc": "remote procedure call",
    "grpc": "google remote procedure call",
    "graphql": "graph query language",
    "cicd": "continuous integration",
    "k8s": "kubernetes",
    "mlops": "machine learning operations",
}

FORBIDDEN_GROUPS = [GAMING_TERMS, CONSUMER_TERMS]


def check_query(query: str, tool_name: str) -> list:
    issues = []
    q_lower = query.lower()

    for group in FORBIDDEN_GROUPS:
        for term in group:
            if term in q_lower:
                issues.append(f"Contains off-domain term '{term}'")

    return issues


def correct_query(query: str, tool_name: str, key: str) -> str:
    q = query
    q_lower = q.lower()

    # Strip gaming terms
    for term in GAMING_TERMS + CONSUMER_TERMS:
        pattern = re.compile(re.escape(term), re.IGNORECASE)
        q = pattern.sub("", q)

    # Collapse multiple spaces
    q = re.sub(r"\s+", " ", q).strip()

    # Ensure tool name is present
    if tool_name.lower() not in q.lower():
        q = f"{tool_name} {q}"

    # If query became too short after stripping, rebuild a safe default
    if len(q.split()) < 3:
        defaults = {
            "community": f"{tool_name} developer community feedback experience",
            "production": f"{tool_name} production deployment real world usage",
            "alternatives": f"{tool_name} alternatives comparison migration",
        }
        q = defaults.get(key, f"{tool_name} {key} developer experience")

    return q.strip()


def execute(params, files):
    queries = params.get("queries", {})
    tool_name = params.get("tool_name", "")

    all_issues = {}
    corrected = {}
    has_issues = False

    for key, query in queries.items():
        issues = check_query(query, tool_name)
        if issues:
            has_issues = True
            all_issues[key] = issues
            corrected[key] = correct_query(query, tool_name, key)
        else:
            corrected[key] = query

    return {
        "validated": not has_issues,
        "issues": all_issues,
        "original_queries": queries,
        "corrected_queries": corrected
    }


if __name__ == "__main__":
    raw = sys.stdin.read().strip()
    params = json.loads(raw) if raw else {}
    print(json.dumps(execute(params, {})))
